import type { ScaleBand, ScaleLinear, ScaleSymLog, ScaleTime } from 'd3-scale';
import { isEmpty } from 'lodash-es';

import { ELLIPSIS_BUFFER } from './get-tick-label-props.js';
import { isBandScale, isSymlogScale } from '../../../utils/detect-scale.js';
import {
  X_AXES_TICK_LINE_OFFSET,
  X_LABEL_AREA,
  Y_AXES_TICK_LINE_OFFSET,
  Y_LABEL_AREA,
} from '../constants.js';

export const getYTickMaxSize = (containerWidth: number, label?: string) => {
  const labelArea = isEmpty(label) ? 0 : Y_LABEL_AREA;

  const maxSize =
    containerWidth - (Y_AXES_TICK_LINE_OFFSET + labelArea) + ELLIPSIS_BUFFER;

  return Math.max(maxSize, 0);
};

export const getXTickMaxSize = (
  containerHeight: number,
  containerWidth: number,
  isTickRotated: boolean,
  scale?:
    | ScaleBand<string>
    | ScaleLinear<number, number>
    | ScaleSymLog<number, number>
    | ScaleTime<number, number>,
  label?: string,
  numTicks?: number,
) => {
  const labelArea = isEmpty(label) ? 0 : X_LABEL_AREA;

  let maxSize = 0;

  if (isTickRotated) {
    maxSize =
      containerHeight - (X_AXES_TICK_LINE_OFFSET + labelArea) + ELLIPSIS_BUFFER;
  } else {
    if (scale && isBandScale(scale)) {
      maxSize = scale.step();
    } else if (
      numTicks !== undefined &&
      numTicks > 0 &&
      scale &&
      !isSymlogScale(scale)
    ) {
      //Ignore Log scales as it's causing early truncation
      maxSize = containerWidth / numTicks;
    } else {
      maxSize = containerWidth;
    }
  }

  return Math.max(maxSize, 0);
};
